binds {
    // Keys consist of modifiers separated by + signs, followed by an XKB key name
    // in the end. To find an XKB name for a particular key, you may use a program
    // like wev.
    //
    // "Mod" is a special modifier equal to Super when running on a TTY, and to Alt
    // when running as a winit window.
    //
    // Most actions that you can bind here can also be invoked programmatically with
    // `niri msg action do-something`.

    // Mod-Shift-/, which is usually the same as Mod-?,
    // shows a list of important hotkeys.
    Mod+Shift+Slash { show-hotkey-overlay; }

    // Suggested binds for running programs: terminal, app launcher, screen locker.
    Ctrl+Shift+Alt+Mod+Space hotkey-overlay-title="Focus/Open Terminal" { spawn-sh "niri-focus-or-open ghostty ghostty"; }
    Mod+Space hotkey-overlay-title="Open Terminal Here" { spawn "ghostty" "--title=local"; }

    Ctrl+Shift+Alt+Mod+Semicolon hotkey-overlay-title="Run an Application: fuzzel" { spawn "fuzzel"; }
    Ctrl+Shift+Alt+Mod+W hotkey-overlay-title="Focus/Open Browser" { spawn-sh "niri-focus-or-open helium helium-browser"; }
    Ctrl+Shift+Alt+Mod+X hotkey-overlay-title="Run an Application: ProtonPass" { spawn "proton-pass"; }
    Ctrl+Shift+Alt+Mod+N hotkey-overlay-title="Focus/Open Notes" { spawn-sh "niri-focus-or-open obsidian obsidian"; }
    Ctrl+Shift+Alt+Mod+A hotkey-overlay-title="Activity" { spawn "ghostty" "-e" "btop"; }
    Ctrl+Shift+Alt+Mod+B hotkey-overlay-title="Bookmarks" { spawn "ghostty" "--title=bm" "-e" "bm" ; }
    Ctrl+Shift+Alt+Mod+V hotkey-overlay-title="Clipboard History" { spawn "ghostty" "--title=clipse" "--maximize=false" "-e" "clipse"; }


    Super+Alt+L hotkey-overlay-title="Lock the Screen: hyprlock" { spawn "hyprlock"; }

    // Voice dictation (hyprwhspr)
    Alt+Space hotkey-overlay-title="Voice Dictation" { spawn "hyprwhspr" "record" "toggle"; }

    // Wallpaper picker
    Mod+Shift+W hotkey-overlay-title="Wallpaper Picker" { spawn "waypaper"; }

    // macOS-style copy/paste/cut (works in terminals too)
    Mod+C repeat=false { spawn-sh "macos-copy-paste copy"; }
    Mod+V repeat=false { spawn-sh "macos-copy-paste paste"; }
    Mod+X repeat=false { spawn-sh "macos-copy-paste cut"; }

    // Use spawn-sh to run a shell command. Do this if you need pipes, multiple commands, etc.
    // Note: the entire command goes as a single argument. It's passed verbatim to `sh -c`.
    // For example, this is a standard bind to toggle the screen reader (btop).

    // Example volume keys mappings for PipeWire & WirePlumber.
    // The allow-when-locked=true property makes them work even when the session is locked.
    // Using spawn-sh allows to pass multiple arguments together with the command.
    // "-l 1.0" limits the volume to 100%.
    XF86AudioRaiseVolume allow-when-locked=true { spawn-sh "wpctl set-volume @DEFAULT_AUDIO_SINK@ 0.1+ -l 1.0"; }
    XF86AudioLowerVolume allow-when-locked=true { spawn-sh "wpctl set-volume @DEFAULT_AUDIO_SINK@ 0.1-"; }
    XF86AudioMute        allow-when-locked=true { spawn-sh "wpctl set-mute @DEFAULT_AUDIO_SINK@ toggle"; }
    XF86AudioMicMute     allow-when-locked=true { spawn-sh "wpctl set-mute @DEFAULT_AUDIO_SOURCE@ toggle"; }

    // Example media keys mapping using playerctl.
    // This will work with any MPRIS-enabled media player.
    XF86AudioPlay        allow-when-locked=true { spawn-sh "playerctl play-pause"; }
    XF86AudioStop        allow-when-locked=true { spawn-sh "playerctl stop"; }
    XF86AudioPrev        allow-when-locked=true { spawn-sh "playerctl previous"; }
    XF86AudioNext        allow-when-locked=true { spawn-sh "playerctl next"; }

    // Example brightness key mappings for brightnessctl.
    // You can use regular spawn with multiple arguments too (to avoid going through "sh"),
    // but you need to manually put each argument in separate "" quotes.
    XF86MonBrightnessUp allow-when-locked=true { spawn "brightnessctl" "--class=backlight" "set" "+10%"; }
    XF86MonBrightnessDown allow-when-locked=true { spawn "brightnessctl" "--class=backlight" "set" "10%-"; }

    // Open/close the Overview: a zoomed-out view of workspaces and windows.
    // You can also move the mouse into the top-left hot corner,
    // or do a four-finger swipe up on a touchpad.
    Mod+S repeat=false { toggle-overview; }

    // Use script for close with confirmation on protected apps (games, etc.)
    Mod+Q repeat=false { spawn-sh "niri-close-window"; }

    Mod+Left  { focus-column-left; }
    Mod+Down  { focus-window-down; }
    Mod+Up    { focus-window-up; }
    Mod+Right { focus-column-right; }
    Mod+H     { focus-column-left; }
    Mod+J     { focus-window-down; }
    Mod+K     { focus-window-up; }
    Mod+L     { focus-column-right; }

    Mod+Ctrl+Left  { move-column-left; }
    Mod+Ctrl+Down  { move-window-down; }
    Mod+Ctrl+Up    { move-window-up; }
    Mod+Ctrl+Right { move-column-right; }
    Mod+Ctrl+H     { move-column-left; }
    Mod+Ctrl+J     { move-window-down; }
    Mod+Ctrl+K     { move-window-up; }
    Mod+Ctrl+L     { move-column-right; }

    // Alternative commands that move across workspaces when reaching
    // the first or last window in a column.
    // Mod+J     { focus-window-or-workspace-down; }
    // Mod+K     { focus-window-or-workspace-up; }
    // Mod+Ctrl+J     { move-window-down-or-to-workspace-down; }
    // Mod+Ctrl+K     { move-window-up-or-to-workspace-up; }

    Mod+Home { focus-column-first; }
    Mod+End  { focus-column-last; }
    Mod+Ctrl+Home { move-column-to-first; }
    Mod+Ctrl+End  { move-column-to-last; }

    // Mod+Shift+Left  { focus-monitor-left; }
    // Mod+Shift+Down  { focus-monitor-down; }
    // Mod+Shift+Up    { focus-monitor-up; }
    // Mod+Shift+Right { focus-monitor-right; }
    // Mod+Shift+H     { focus-monitor-left; }
    // Mod+Shift+J     { focus-monitor-down; }
    // Mod+Shift+K     { focus-monitor-up; }
    // Mod+Shift+L     { focus-monitor-right; }

    Mod+Shift+Ctrl+Left  { move-column-to-monitor-left; }
    Mod+Shift+Ctrl+Down  { move-column-to-monitor-down; }
    Mod+Shift+Ctrl+Up    { move-column-to-monitor-up; }
    Mod+Shift+Ctrl+Right { move-column-to-monitor-right; }
    Mod+Shift+Ctrl+H     { move-column-to-monitor-left; }
    Mod+Shift+Ctrl+J     { move-column-to-monitor-down; }
    Mod+Shift+Ctrl+K     { move-column-to-monitor-up; }
    Mod+Shift+Ctrl+L     { move-column-to-monitor-right; }

    // Alternatively, there are commands to move just a single window:
    // Mod+Shift+Ctrl+Left  { move-window-to-monitor-left; }
    // ...

    // And you can also move a whole workspace to another monitor:
    // Mod+Shift+Ctrl+Left  { move-workspace-to-monitor-left; }
    // ...

    Mod+Shift+J      { focus-workspace-down; }
    Mod+Shift+K        { focus-workspace-up; }
    Mod+Ctrl+Page_Down { move-column-to-workspace-down; }
    Mod+Ctrl+Page_Up   { move-column-to-workspace-up; }
    Mod+Ctrl+U         { move-column-to-workspace-down; }
    Mod+Ctrl+I         { move-column-to-workspace-up; }

    // Alternatively, there are commands to move just a single window:
    // Mod+Ctrl+Page_Down { move-window-to-workspace-down; }
    // ...

    Mod+Shift+Page_Down { move-workspace-down; }
    Mod+Shift+Page_Up   { move-workspace-up; }
    Mod+Shift+U         { move-workspace-down; }
    Mod+Shift+I         { move-workspace-up; }

    // You can bind mouse wheel scroll ticks using the following syntax.
    // These binds will change direction based on the natural-scroll setting.
    //
    // To avoid scrolling through workspaces really fast, you can use
    // the cooldown-ms property. The bind will be rate-limited to this value.
    // You can set a cooldown on any bind, but it's most useful for the wheel.
    Mod+WheelScrollDown      cooldown-ms=150 { focus-workspace-down; }
    Mod+WheelScrollUp        cooldown-ms=150 { focus-workspace-up; }
    Mod+Ctrl+WheelScrollDown cooldown-ms=150 { move-column-to-workspace-down; }
    Mod+Ctrl+WheelScrollUp   cooldown-ms=150 { move-column-to-workspace-up; }

    Mod+WheelScrollRight      { focus-column-right; }
    Mod+WheelScrollLeft       { focus-column-left; }
    Mod+Ctrl+WheelScrollRight { move-column-right; }
    Mod+Ctrl+WheelScrollLeft  { move-column-left; }

    // Usually scrolling up and down with Shift in applications results in
    // horizontal scrolling; these binds replicate that.
    Mod+Shift+WheelScrollDown      { focus-column-right; }
    Mod+Shift+WheelScrollUp        { focus-column-left; }
    Mod+Ctrl+Shift+WheelScrollDown { move-column-right; }
    Mod+Ctrl+Shift+WheelScrollUp   { move-column-left; }

    // Similarly, you can bind touchpad scroll "ticks".
    // Touchpad scrolling is continuous, so for these binds it is split into
    // discrete intervals.
    // These binds are also affected by touchpad's natural-scroll, so these
    // example binds are "inverted", since we have natural-scroll enabled for
    // touchpads by default.
    // Mod+TouchpadScrollDown { spawn-sh "wpctl set-volume @DEFAULT_AUDIO_SINK@ 0.02+"; }
    // Mod+TouchpadScrollUp   { spawn-sh "wpctl set-volume @DEFAULT_AUDIO_SINK@ 0.02-"; }

    // You can refer to workspaces by index. However, keep in mind that
    // niri is a dynamic workspace system, so these commands are kind of
    // "best effort". Trying to refer to a workspace index bigger than
    // the current workspace count will instead refer to the bottommost
    // (empty) workspace.
    //
    // For example, with 2 workspaces + 1 empty, indices 3, 4, 5 and so on
    // will all refer to the 3rd workspace.
    Mod+1 { focus-workspace "01"; }
    Mod+2 { focus-workspace "02"; }
    Mod+3 { focus-workspace "03"; }
    Mod+4 { focus-workspace "04"; }
    Mod+5 { focus-workspace "05"; }
    Mod+6 { focus-workspace "06"; }
    Mod+7 { focus-workspace "07"; }
    Mod+8 { focus-workspace "08"; }
    Mod+9 { focus-workspace "09"; }
    Mod+Ctrl+1 { move-column-to-workspace "01"; }
    Mod+Ctrl+2 { move-column-to-workspace "02"; }
    Mod+Ctrl+3 { move-column-to-workspace "03"; }
    Mod+Ctrl+4 { move-column-to-workspace "04"; }
    Mod+Ctrl+5 { move-column-to-workspace "05"; }
    Mod+Ctrl+6 { move-column-to-workspace "06"; }
    Mod+Ctrl+7 { move-column-to-workspace "07"; }
    Mod+Ctrl+8 { move-column-to-workspace "08"; }
    Mod+Ctrl+9 { move-column-to-workspace "09"; }

    // Alternatively, there are commands to move just a single window:
    // Mod+Ctrl+1 { move-window-to-workspace 1; }

    // Switches focus between the current and the previous workspace.
    // Mod+Tab { focus-workspace-previous; }

    // The following binds move the focused window in and out of a column.
    // If the window is alone, they will consume it into the nearby column to the side.
    // If the window is already in a column, they will expel it out.
    Mod+BracketLeft  { consume-or-expel-window-left; }
    Mod+BracketRight { consume-or-expel-window-right; }

    // Consume one window from the right to the bottom of the focused column.
    Mod+Comma  { consume-window-into-column; }
    // Expel the bottom window from the focused column to the right.
    Mod+Period { expel-window-from-column; }

    Mod+R { switch-preset-column-width; }
    // Cycling through the presets in reverse order is also possible.
    // Mod+R { switch-preset-column-width-back; }
    Mod+Shift+R { switch-preset-window-height; }
    Mod+Ctrl+R { reset-window-height; }
    Mod+F { maximize-column; }
    Mod+Shift+F { fullscreen-window; }

    // Expand the focused column to space not taken up by other fully visible columns.
    // Makes the column "fill the rest of the space".
    Mod+Ctrl+F { expand-column-to-available-width; }

    Mod+Shift+C { center-column; }

    // Center all fully visible columns on screen.
    Mod+Shift+Ctrl+C { center-visible-columns; }

    // Mod+Minus/Equal freed up for Super+-/= from Moonlander (zoom in Ghostty)
    // Use Mod+R for preset column widths, Mod+Shift+R / Mod+Ctrl+R for window heights

    // Move the focused window between the floating and the tiling layout.
    // Move window between floating and tiling layout
    Mod+T       { toggle-window-floating; }
    Mod+Shift+T { switch-focus-between-floating-and-tiling; }

    // Toggle tabbed column display mode.
    // Windows in this column will appear as vertical tabs,
    // rather than stacked on top of each other.
    Mod+W { toggle-column-tabbed-display; }

    // Actions to switch layouts.
    // Note: if you uncomment these, make sure you do NOT have
    // a matching layout switch hotkey configured in xkb options above.
    // Having both at once on the same hotkey will break the switching,
    // since it will switch twice upon pressing the hotkey (once by xkb, once by niri).
    // Mod+Space       { switch-layout "next"; }
    // Mod+Shift+Space { switch-layout "prev"; }

    // Screenshots using niri native + satty
    // Mod+Shift+1: Full screen → Satty
    // Mod+Shift+2: Focused window → Satty
    // Mod+Shift+3: Select area → Satty
    Mod+Shift+1 { spawn-sh "niri msg action screenshot-screen --write-to-disk=false && wl-paste | satty -f -"; }
    Mod+Shift+2 { spawn-sh "niri msg action screenshot-window --write-to-disk=false && wl-paste | satty -f -"; }
    Mod+Shift+3 { spawn-sh "niri msg action screenshot && wl-paste | satty -f -"; }

    // Applications such as remote-desktop clients and software KVM switches may
    // request that niri stops processing the keyboard shortcuts defined here
    // so they may, for example, forward the key presses as-is to a remote machine.
    // It's a good idea to bind an escape hatch to toggle the inhibitor,
    // so a buggy application can't hold your session hostage.
    //
    // The allow-inhibiting=false property can be applied to other binds as well,
    // which ensures niri always processes them, even when an inhibitor is active.
    Mod+Escape allow-inhibiting=false { toggle-keyboard-shortcuts-inhibit; }

    // Power menu with lock, logout, suspend, reboot, shutdown options
    Mod+Shift+E { spawn-sh "niri-power-menu"; }

    // Reload niri config and waybar
    Ctrl+Alt+Shift+R { spawn-sh "killall waybar; niri msg action reload-config; waybar &"; }

    Ctrl+Alt+Delete { quit; }

    // Powers off the monitors. To turn them back on, do any input like
    // moving the mouse or pressing any other key.
    Mod+Shift+P { power-off-monitors; }
}

    // Suggested binds for running programs: terminal, app launcher, screen locker.
    Ctrl+Shift+Alt+Mod+Space hotkey-overlay-title="Focus/Open Terminal" { spawn-sh "niri-focus-or-open ghostty ghostty"; }
    Mod+Space hotkey-overlay-title="Open Terminal Here" { spawn "ghostty" "--title=local"; }

    Ctrl+Shift+Alt+Mod+Semicolon hotkey-overlay-title="Run an Application: fuzzel" { spawn "fuzzel"; }
    Ctrl+Shift+Alt+Mod+W hotkey-overlay-title="Focus/Open Browser" { spawn-sh "niri-focus-or-open helium helium-browser"; }
    Ctrl+Shift+Alt+Mod+X hotkey-overlay-title="Run an Application: ProtonPass" { spawn "proton-pass"; }
    Ctrl+Shift+Alt+Mod+N hotkey-overlay-title="Focus/Open Notes" { spawn-sh "niri-focus-or-open obsidian obsidian"; }
    Ctrl+Shift+Alt+Mod+A hotkey-overlay-title="Activity" { spawn "ghostty" "-e" "btop"; }
    Ctrl+Shift+Alt+Mod+B hotkey-overlay-title="Bookmarks" { spawn "ghostty" "--title=bm" "-e" "bm" ; }
    Ctrl+Shift+Alt+Mod+V hotkey-overlay-title="Clipboard History" { spawn "ghostty" "--title=clipse" "--maximize=false" "-e" "clipse"; }


    Super+Alt+L hotkey-overlay-title="Lock the Screen: hyprlock" { spawn "hyprlock"; }

